<?php defined('ABSPATH') || exit; class FounderKit_Blocks { private static ?FounderKit_Blocks $instance=null; public static function instance(): self { if(!self::$instance) self::$instance=new self(); return self::$instance; } public function __construct(){ add_action('init',[$this,'register_category']); add_action('init',[$this,'register_all']); add_action('enqueue_block_assets',[$this,'enqueue_shared_assets']); } public function register_category(): void { do_action('founderkit_before_register_block_category'); add_filter('block_categories_all', function($cats){ $cats[]=['slug'=>'founderkit','title'=>__('FounderKit','founderkit')]; return $cats; }); do_action('founderkit_after_register_block_category'); } public function get_all(): array { $blocks=['hero','stats-counter','case-study','portfolio-grid','tech-stack','pricing-table','quiz-embed','course-card','timeline','digital-product-card','testimonial-carousel','job-listing','team-member','membership-cta','resource-card']; return apply_filters('founderkit_available_blocks',$blocks); } public function register_all(): void { do_action('founderkit_before_register_blocks'); $settings=new FounderKit_Settings(); $blocks=$this->get_all(); foreach($blocks as $slug){ do_action('founderkit_before_register_block',$slug); if(!$settings->is_block_enabled('fk-'.$slug)) continue; $dir=FOUNDERKIT_PATH.'blocks/'.$slug; if(file_exists($dir.'/block.json')) register_block_type($dir); do_action('founderkit_after_register_block',$slug); } do_action('founderkit_after_register_blocks'); } public function enqueue_shared_assets(): void { do_action('founderkit_before_enqueue_block_assets'); $deps=apply_filters('founderkit_asset_dependencies',[]); wp_register_style('founderkit-style', FOUNDERKIT_URL.'assets/css/founderkit.css', $deps, FOUNDERKIT_VERSION); wp_register_style('founderkit-editor', FOUNDERKIT_URL.'assets/css/editor.css', $deps, FOUNDERKIT_VERSION); wp_register_script('founderkit-frontend', FOUNDERKIT_URL.'assets/js/founderkit.js', $deps, FOUNDERKIT_VERSION, true); wp_enqueue_style('founderkit-style'); wp_enqueue_script('founderkit-frontend'); $data=apply_filters('founderkit_frontend_data',['ajaxUrl'=>admin_url('admin-ajax.php'),'nonce'=>wp_create_nonce('founderkit_nonce')]); wp_localize_script('founderkit-frontend','founderKitData',$data); do_action('founderkit_after_enqueue_block_assets'); } }
